INSERT INTO aggregate.additives (code, url, name_lt, is_dangerous, general_usage_in_food_industry_lt, usage_in_foods_lt, other_information_lt, damage_lt, name_en, general_usage_in_food_industry_en, usage_in_foods_en, other_information_en, damage_en)
VALUES
    ('E493', 'http://konservantai.lt/e493-sorbitano-monolauratas', 'Sorbitano monolauratas', TRUE, 'Artificial emulsifier and stabilizer.', 'In baked goods, jams, dairy and cream substitutes, liquid fruit and herbal concentrates, ice creams, sauces, chewing gum, dietary products.', 'Banned in some countries (USA, Canada, Australia/New Zealand).', 'A - allergy, asthma (especially to be avoided by those allergic and asthmatic);', 'Sorbitan Monolaurate', 'Artificial emulsifier and stabilizer.', 'In baked goods, jams, dairy and cream substitutes, liquid fruit and herbal concentrates, ice creams, sauces, chewing gum, dietary products.', 'Banned in some countries (USA, Canada, Australia/New Zealand).', 'A - allergy, asthma (especially to be avoided by those allergic and asthmatic);'),
    ('E472e', 'http://konservantai.lt/e472e-riebalu-rugsciu-monogliceridu-ir-digliceridu-monoacetilvyno-ir-diacetilvyno-rugsties-esteriai', 'Riebalų rūgščių monogliceridų ir digliceridų monoacetilvyno ir diacetilvyno rūgšties esteriai', TRUE, 'Emulsiklis, stabilizatorius ir miltų apdorojimo medžiaga. Padaro gaminį puresnį, didesnio tūrio, vientisesnės formos, ilgiau išliekantį šviežią.', 'Kepiniuose, karšto šokolado mišiniuose, šaldytoje picoje.', '', 'T - gali būti gyvulinės kilmės;', 'Esters of Monoglycerides and Diglycerides of Fatty Acids Monoacetylated and Diacetylated', 'Emulsifier, stabilizer, and flour treatment agent. Increases product fluffiness, volume, uniformity, and freshness duration.', 'In baked goods, hot chocolate mixes, frozen pizza.', '', 'T - may be of animal origin;'),
    ('E312', 'http://konservantai.lt/e312-dodecilgalatas', 'Dodecilgalatas', FALSE, '', 'Dribsniuose, grūduose, sūryje, salotų padažuose, riebaluose, aliejuose.', '', 'A - alergija, astma (ypač reikia vengti alergiškiems ir sergantiems astma);', 'Dodecyl Gallate', '', 'In flakes, grains, brine, salad dressings, fats, oils.', '', 'A - allergy, asthma (especially to be avoided by those allergic and asthmatic);'),
    ('E340', 'http://konservantai.lt/e340-monokalio-fosfatas-dikalio-fosfatas-trikalio-fosfatas', 'Monokalio fosfatas, dikalio fosfatas, trikalio fosfatas', FALSE, 'Rūgštingumą reguliuojanti medžiaga, emulsiklis, stabilizatorius.', 'Virtoje ar konservuotoje mėsoje, pieno, grietinėlės milteliuose, geriamajame šokolade, želės produktuose.', '', 'A - alergija, astma (ypač reikia vengti alergiškiems ir sergantiems astma);', 'Mono Potassium Phosphate, Di Potassium Phosphate, Tri Potassium Phosphate', 'Acid regulator, emulsifier, stabilizer.', 'In cooked or canned meat, milk, cream powder, drinking chocolate, jelly products.', '', 'A - allergy, asthma (especially to be avoided by those allergic and asthmatic);'),
    ('E334', 'http://konservantai.lt/e334-vyno-rugstis-l', 'Vyno rūgštis (L)', TRUE, 'Rūgštingumą reguliuojanti medžiaga, antioksidatorius.', 'Želatinoje, dešroje, gėrimuose, desertuose, tirpiose tabletėse, kepimo milteliuose.', '', 'Gen - genetiškai modifikuoti organizmai;', 'Tartaric Acid (L)', 'Acidulant, antioxidant.', 'In gelatin, sausages, beverages, desserts, effervescent tablets, baking powders.', '', 'Gen - genetically modified organisms;'),
    ('E407', 'http://konservantai.lt/e407-karageninas', 'Karageninas', TRUE, 'Thickener, gelling agent, stabilizer.', 'In dairy products, puddings, glazes, as well as in toothpaste and creams.', '', '', 'Carrageenan', 'Thickener, gelling agent, stabilizer.', 'In dairy products, puddings, glazes, as well as in toothpaste and creams.', '', ''),
    ('E627', 'http://konservantai.lt/e627-dinatrio-guanilatas', 'Dinatrio guanilatas', TRUE, '', 'Greitai paruošiamuose makaronuose, bulvių traškučiuose ir užkandžiuose, pikantiškuose ryžiuose, konservuotoje mėsoje, sriuboje pakeliuose.', '', 'A - alergija, astma (ypač reikia vengti alergiškiems ir sergantiems astma);', 'Disodium Guanylate', '', 'In instant noodles, potato chips and snacks, savory rice, canned meat, and powdered soup.', '', 'A - allergy, asthma (especially to be avoided by those allergic and asthmatics);'),
    ('E290', 'http://konservantai.lt/e290-anglies-dioksidas', 'Anglies dioksidas', TRUE, 'Natūrali konservavimo medžiaga, įpakavimo dujos arba rūgštingumą reguliuojanti medžiaga.', 'Gėrimuose. Šiomis dujomis įpakuojami kepiniai, sūriai, konditerija.', '', '', 'Carbon Dioxide', 'Natural preservative, packaging gas, or acidity regulator.', 'In beverages. These gases are used to package baked goods, cheeses, and confectionery.', '', ''),
    ('E316', 'http://konservantai.lt/e316-natrio-eritorbatas', 'Natrio eritorbatas', TRUE, '', 'Nealkoholiniuose gėrimuose, mėsoje, paukštienoje.', '', 'A - alergija, astma (ypač reikia vengti alergiškiems ir sergantiems astma);', 'Sodium Erythorbate', '', 'In non-alcoholic beverages, meat, poultry.', '', 'A - allergy, asthma (especially to be avoided by allergic and asthmatic individuals);'),
    ('E331', 'http://konservantai.lt/e331-mononatrio-citratas-dinatrio-citratas-trinatrio-citratas', 'Mononatrio citratas, dinatrio citratas, trinatrio citratas', TRUE, 'Rūgštingumą reguliuojanti medžiaga, emulsiklis, stabilizatorius.', 'Uogienėje, saldainiuose, leduose, lydytame sūryje, pieno milteliuose, gazuotuose, gėrimuose, vyne.', '', 'A - alergija, astma (ypač reikia vengti alergiškiems ir sergantiems astma);', 'Monosodium citrate, disodium citrate, triosodium citrate', 'Acid regulator, emulsifier, stabilizer.', 'In jams, candies, ice creams, processed cheese, milk powders, carbonated drinks, wine.', '', 'A - allergy, asthma (especially avoid for allergic individuals and asthma patients);'),
    ('E955', 'http://konservantai.lt/e955-sukraloze', 'Sukralozė', TRUE, 'Artificial sweetener, 400–800 times sweeter than sugar.', 'In fruit beverages, culinary products.', '', '', 'Sucralose', 'Artificial sweetener, 400–800 times sweeter than sugar.', 'In fruit beverages, culinary products.', '', ''),
    ('E227', 'http://konservantai.lt/e227-kalcio-rugstusis-sulfitas', 'Kalcio rūgštusis sulfitas', TRUE, 'Konservantas, antioksidantas.', 'Džiovintuose vaisiuose ir riešutuose, vaisių konservuose, paruoštuose krienuose, bulvių gaminiuose, vyne, kepimo milteliuose, dešroje, saldumynuose, aliejuje, aluje, gaiviuosiuose gėrimuose, acte.', 'Kai kuriose šalyse uždraustas (JAV, Kanadoje, Australijoje / Naujojoje Zelandijoje).', 'A - alergija, astma (ypač reikia vengti alergiškiems ir sergantiems astma);', 'Calcium Acid Sulfite', 'Preservative, antioxidant.', 'In dried fruits and nuts, fruit preserves, prepared horseradish, potato products, wine, baking powder, sausages, sweets, oil, beer, soft drinks, vinegar.', 'Banned in some countries (USA, Canada, Australia/New Zealand).', 'A - allergy, asthma (especially to be avoided by those allergic and asthmatic);'),
    ('E435', 'http://konservantai.lt/e435-polioksietileno-sorbitano-monostearatas-polisorbatas-60', 'Polioksietileno sorbitano  monostearatas (polisorbatas 60)', FALSE, '', 'Kepiniuose, šaldytuose desertuose, pieno produktų pakaitaluose.', '', 'A - alergija, astma (ypač reikia vengti alergiškiems ir sergantiems astma);', 'Polyoxyethylene Sorbitan Monostearate (Polysorbate 60)', '', 'In baked goods, frozen desserts, milk product substitutes.', '', 'A - allergy, asthma (especially to be avoided by those allergic and suffering from asthma);'),
    ('E160a', 'http://konservantai.lt/e160a-karotenu-misinys-beta-karotenas', 'Karotenų mišinys, beta karotenas', TRUE, '', 'Svieste, margarine, sriubose, majoneze, pudinguose, saldumynuose, jogurte, morkose, kituose geltonuose vaisiuose ir daržovėse.', '', '', 'Carotene Mixture, Beta Carotene', '', 'In butter, margarine, soups, mayonnaise, puddings, confections, yogurt, carrots, and other yellow fruits and vegetables.', '', ''),
    ('E999', 'http://konservantai.lt/e999-kualajos-ekstraktas', 'Kualajos ekstraktas', TRUE, 'Used as a natural sweetener, preservative, thickening agent, natural foaming agent.', 'In beer, soft drinks.', 'Banned in some countries (Canada).', 'A - allergy, asthma (especially to be avoided by those allergic and suffering from asthma);', 'Kualajos Extract', 'Used as a natural sweetener, preservative, thickening agent, natural foaming agent.', 'In beer, soft drinks.', 'Banned in some countries (Canada).', 'A - allergy, asthma (especially to be avoided by those allergic and suffering from asthma);'),
    ('E938', 'http://konservantai.lt/e938-argonas', 'Argonas', TRUE, 'Duonos gaminių kildiklis, miltų balinimo medžiaga.', 'Duonoje, miltuose.', '', '', 'Argon', 'Bread dough rising agent, flour bleaching agent.', 'In bread, in flour.', '', ''),
    ('E514', 'http://konservantai.lt/e514-natrio-sulfatas-natrio-rugstusis-sulfatas', 'Natrio sulfatas, natrio rūgštusis sulfatas', TRUE, 'Sieros rūgšties druskos, žinoma kaip Glauberio druska.', 'Aluje, kramtomojoje gumoje, konditerijos gaminiuose.', '', '', 'Sodium Sulfate, Sodium Acid Sulfate', 'Salts of sulfuric acid, known as Glauber''s salt.', 'In beer, chewing gum, confectionery products.', '', ''),
    ('E1442', 'http://konservantai.lt/e1442-hidroksipropildikrakmolo-fosfatas', 'Hidroksipropildikrakmolo fosfatas', FALSE, 'Natūrali tirštinanti ir stingdanti medžiaga, stabilizatorius.', '', '', 'Gen - genetiškai modifikuoti organizmai;', 'Hydroxypropyl Starch Phosphate', 'Natural thickening and gelling agent, stabilizer.', '', '', 'Gen - genetically modified organisms;'),
    ('E410', 'http://konservantai.lt/e410-saldziuju-ceratoniju-derva', 'Saldžiųjų ceratonijų derva', TRUE, '', 'Glajuje, kepiniuose, pieno kokteiliuose, kaip kakavos pakaitalas.', '', '', 'Carob Bean Gum', '', 'In glazes, baked goods, milkshakes, as a cocoa substitute.', '', ''),
    ('E150b', 'http://konservantai.lt/e150b-sarmine-sulfitine-karamele', 'Šarminė sulfitinė karamelė', TRUE, '', 'Konjake, ispaniškame vyne, kai kurios rūšies acte.', '', '', 'Alkaline Sulphite Caramel', '', 'In cognac, Spanish wine, certain types of vinegar.', '', ''),
    ('E476', 'http://konservantai.lt/e476-poliglicerolio-poliricinoleatas', 'Poliglicerolio poliricinoleatas', TRUE, 'Dirbtinis emulsiklis ir stabilizatorius.', 'Glajuje, pyragų mišiniuose, neriebiuose užtepėlėse ir padažuose, konditerijos gaminiuose iš kakavos ar šokolado.', '', 'Gen - genetiškai modifikuoti organizmai;', 'Polyglycerol Polyricinoleate', 'Artificial emulsifier and stabilizer.', 'In glazes, cake mixes, low-fat spreads and sauces, confectionery products made from cocoa or chocolate.', '', 'GM - genetically modified organisms;'),
    ('E280', 'http://konservantai.lt/e280-propiono-rugstis', 'Propiono rūgštis', FALSE, '', 'Duonoje, sausainiuose ir fasuotuose kepiniuose.', 'Propiono rūgštis ir jos dariniai. Vokietijoje, Šveicarijoje ir Austrijoje buvo uždrausti kaip nereikalingi ir gadinantys skonį, dabar ES šalyse ją vėl leidžiama vartoti.', 'A - alergija, astma (ypač reikia vengti alergiškiems ir sergantiems astma);', 'Propionic Acid', '', 'In bread, cookies, and packaged baked goods.', 'Propionic acid and its derivatives. Banned in Germany, Switzerland, and Austria as unnecessary and flavor-detracting; now allowed again in EU countries.', 'A - allergy, asthma (especially to be avoided by those allergic and suffering from asthma);'),
    ('E471', 'http://konservantai.lt/e471-riebalu-rugsciu-monogliceridai-ir-digliceridai', 'Riebalų rūgščių monogliceridai ir digliceridai', TRUE, 'Emulsiklis, stabilizatorius, miltų apdorojimo medžiaga.', 'Karšto šokolado, greitai paruošiamo saldaus kremo mišiniuose, tortų mišiniuose, dehidratuotoje bulvių košėje, forminiuose traškučiuose, purškiamoje grietinėlėje, putėsių mišiniuose.', '', 'T - gali būti gyvulinės kilmės;', 'Fatty Acid Monoglycerides and Diglycerides', 'Emulsifier, stabilizer, flour processing agent.', 'In hot chocolate, instant sweet cream mixtures, cake mixes, dehydrated potato mash, shaped chips, whipped cream, and mousse mixtures.', '', 'T - may be of animal origin;'),
    ('E218', 'http://konservantai.lt/e218-metilo-p-hidroksibenzoatas', 'Metilo p-hidroksibenzoatas', FALSE, '', 'Vaisiuose, grybuose, cinamone, gvazdikėliuose ir kai kuriuose pieno produktuose.', '', '', 'Methyl p-hydroxybenzoate', '', 'In fruits, mushrooms, cinnamon, cloves, and some dairy products.', '', ''),
    ('E902', 'http://konservantai.lt/e902-kandelila-vaskas', 'Kandelila vaškas', TRUE, '', 'Blizgintivaisiams ir daržovėms.', '', '', 'Candelilla Wax', '', 'To polish fruits and vegetables.', '', ''),
    ('E407a', 'http://konservantai.lt/e407a-perdirbti-eucheuma-juros-dumbliai', 'Perdirbti eucheuma jūros dumbliai', TRUE, 'Thickener, stabilizer.', '', '', '', 'Processed Euchema Seaweed', 'Thickener, stabilizer.', '', '', ''),
    ('E475', 'http://konservantai.lt/e475-riebalu-rugsciu-poliglicerolio-esteriai', 'Riebalų rūgščių poliglicerolio esteriai', TRUE, 'Dirbtinis emulsiklis ir stabilizatorius.', 'Glajuje, pyragų mišiniuose, leduose ir kituose desertuose, kepiniuose ir kituose produktuose iš tešlos, kramtomojoje gumoje, kavos balikliuose, svieste, pieno pakaitaluose.', '', 'T - gali būti gyvulinės kilmės;', 'Fatty Acid Polyglycerol Esters', 'Artificial emulsifier and stabilizer.', 'In glazes, cake mixes, ice creams and other desserts, baked goods and other dough products, chewing gum, coffee whiteners, butter, milk substitutes.', '', 'T - may be of animal origin;'),
    ('E237', 'http://konservantai.lt/e237-natrio-formatas', 'Natrio formatas', FALSE, 'Konservantas, skruzdžių rūgšties natrio natūrali druska.', '', '', '', 'Sodium Format', 'Preservative, natural salt of sodium formate.', '', '', ''),
    ('E650', 'http://konservantai.lt/e650-cinko-acetatas', 'Cinko acetatas', TRUE, '', '', '', '', 'Zinc Acetate', '', '', '', ''),
    ('E356', 'http://konservantai.lt/e356-natrio-adipatas', 'Natrio adipatas', TRUE, '', 'Valgomosios druskos pakaitalas.', '', '', 'Sodium Adipate', '', 'Substitute for table salt.', '', ''),
    ('E966', 'http://konservantai.lt/e966-laktitolis', 'Laktitolis', TRUE, '', '', '', '', 'Lactitol', '', '', '', ''),
    ('E965', 'http://konservantai.lt/e965-maltitolis-maltitolio-sirupas', 'Maltitolis, maltitolio sirupas', TRUE, '', 'Marcipanuose ir saldumynuose.', '', '', 'Maltitol, Maltitol Syrup', '', 'In marzipan and confectionery.', '', ''),
    ('E332', 'http://konservantai.lt/e332-monokalio-citratas-trikalio-citratas', 'Monokalio citratas, trikalio citratas', TRUE, 'Rūgštingumą reguliuojanti medžiaga, stabilizatorius.', 'Uogienėje, saldainiuose, leduose, lydytame sūryje, pieno milteliuose, gazuotuose, gėrimuose, vyne.', '', 'A - alergija, astma (ypač reikia vengti alergiškiems ir sergantiems astma);', 'Monopotassium citrate, Tricalcium citrate', 'Acid regulator, stabilizer.', 'In jams, candies, ice creams, processed cheese, milk powders, carbonated beverages, and wine.', '', 'A - allergy, asthma (particularly to be avoided by those allergic and suffering from asthma);'),
    ('E903', 'http://konservantai.lt/e903-karnauba-vaskas', 'Karnauba vaškas', TRUE, '', 'Šokolade, kakavos produktuose, kramtomojoje gumoje, konditerijos gaminiuose, pikantiškuose užkandžiuose.', '', '', 'Carnauba Wax', '', 'In chocolate, cocoa products, chewing gum, confectionery products, savory snacks.', '', ''),
    ('E907', 'http://konservantai.lt/e907-hidrintas-poli-1-decenas', 'Hidrintas poli-1-decenas', FALSE, '', 'Naudojama kaip apsauginis sluoksnis apdorojant šviežius vaisius, daržoves bei kitus produktus, kuriems reikia blizgaus paviršiaus. Taip pat naudojama kramtomojoje gumoje, tablečių apvalkaluose.', '', '', 'Hydrogenated Poly-1-Decene', '', 'Used as a protective layer when processing fresh fruits, vegetables, and other products that require a shiny surface. Also used in chewing gum and tablet coatings.', '', ''),
    ('E352', 'http://konservantai.lt/e352-kalcio-malatas-kalcio-rugstusis-malatas', 'Kalcio malatas, kalcio rūgštusis malatas', TRUE, '', 'Vaisių sulčių ir nealkoholiniuose gėrimuose, pieno mišiniuose.', '', '', 'Calcium Malate, Calcium Acid Malate', '', 'In fruit juices and non-alcoholic beverages, milk mixtures.', '', ''),
    ('E415', 'http://konservantai.lt/e415-ksantano-derva', 'Ksantano derva', TRUE, 'Tirštiklis, stingdiklis, stabilizatorius.', 'Salotų padažuose, garstyčiose, kosmetikoje.', '', '', 'Xanthan Gum', 'Thickener, gelling agent, stabilizer.', 'In salad dressings, mustards, cosmetics.', '', ''),
    ('E1517', 'http://konservantai.lt/e1517-glicerildiacetatas-diacetinas', 'Glicerildiacetatas (diacetinas)', TRUE, 'Kvapiųjų medžiagų nešiklis, tirpiklis.', 'Svieste.', '', '', 'Glycerol Diacetate (Diacetin)', 'Carrier for flavoring substances, solvent.', 'In butter.', '', ''),
    ('E633', 'http://konservantai.lt/e633-kalcio-inozinatas', 'Kalcio inozinatas', TRUE, '', 'Mažai druskos ir sodos turinčiuose produktuose.', 'Kai kuriose šalyse uždraustas (JAV, Kanadoje, Australijoje / Naujojoje Zelandijoje).', 'A - alergija, astma (ypač reikia vengti alergištiems ir sergantiems astma);', 'Calcium Inosinate', '', 'In products low in salt and sodium.', 'Banned in some countries (USA, Canada, Australia/New Zealand).', 'A - allergy, asthma (especially avoid for those allergic and asthmatic);'),
    ('E262', 'http://konservantai.lt/e262-natrio-acetatas-natrio-rugstusis-acetatas-natrio-diacetatas', 'Natrio acetatas, natrio rūgštusis acetatas (natrio diacetatas)', TRUE, 'Artificial acidity regulator and preservative.', 'In snacks, bread, as a flavor enhancer in bread, pastries, cheese.', '', '', 'Sodium acetate, sodium acid acetate (sodium diacetate)', 'Artificial acidity regulator and preservative.', 'In snacks, bread, as a flavor enhancer in bread, pastries, cheese.', '', ''),
    ('E129', 'http://konservantai.lt/e129-alura-raudonasis-ac', 'Alura raudonasis AC', TRUE, '', 'Saldainiuose, gėrimuose, prieskoniuose, vaistuose.', 'Kai kuriose šalyse uždraustas.', '', 'Alura Red AC', '', 'In candies, beverages, seasonings, and pharmaceuticals.', 'Banned in some countries.', ''),
    ('E219', 'http://konservantai.lt/e219-natrio-metilo-p-hidroksibenzoatas', 'Natrio metilo p-hidroksibenzoatas', TRUE, '', 'Vaisiuose, grybuose, cinamone, gvazdikėliuose ir kai kuriuose pieno produktuose.', 'Kai kuriose šalyse uždraustas (JAV, Kanadoje, Australijoje / Naujojoje Zelandijoje).', '', 'Sodium Methyl p-Hydroxybenzoate', '', 'In fruits, mushrooms, cinnamon, cloves, and some dairy products.', 'Banned in some countries (USA, Canada, Australia/New Zealand).', ''),
    ('E355', 'http://konservantai.lt/e355-adipo-rugstis', 'Adipo rūgštis', TRUE, '', 'Kepimo milteliuose, uogienėje, margarine, aluje, vaisių gėrimuose.', '', '', 'Adipic Acid', '', 'In baking powders, jams, margarine, beer, fruit beverages.', '', ''),
    ('E306', 'http://konservantai.lt/e306-tokoferoliu-koncentruotas-ekstraktas', 'Tokoferolių koncentruotas ekstraktas', TRUE, 'Antioksidantas, spalvų fiksatorius, vitaminų priedas, ekstrahuotas iš augalinio aliejaus. Galimos kryžminės reakcijos su kitais vitaminais, todėl reikia neperdozuoti. Galimos pavojingos reakcijos su E307–309.', 'Majoneze, margarine, dešroje, desertuose.', '', '', 'Tocopherol Concentrated Extract', 'Antioxidant, color fixative, vitamin additive, extracted from vegetable oil. Possible cross-reactions with other vitamins, thus should not be overdosed. Potentially dangerous reactions with E307–309.', 'In mayonnaise, margarine, sausage, desserts.', '', ''),
    ('E927b', 'http://konservantai.lt/e927b-karbamidas', 'Karbamidas', TRUE, 'Miltų apdorojimo medžiaga, natūralus stabilizatorius.', 'Kramtomojoje gumoje.', 'Kai kuriose šalyse uždraustas (Australijoje / Naujojoje Zelandijoje).', '', 'Urea', 'Flour processing agent, natural stabilizer.', 'In chewing gum.', 'Banned in some countries (Australia/New Zealand).', ''),
    ('E1520', 'http://konservantai.lt/e1520-propan-1-2-diolis', 'Propan-1,2-diolis', TRUE, '', 'Tepamuose valgomuosiuose kremuose.', '', '', 'Propan-1,2-diol', '', 'In spreadable edible creams.', '', ''),
    ('E472c', 'http://konservantai.lt/e472c-riebalu-rugsciu-monogliceridu-ir-digliceridu-citrinu-rugsties-esteriai', 'Riebalų rūgščių monogliceridų ir digliceridų citrinų rūgšties esteriai', TRUE, 'Emulsifier, stabilizer, flour processing agent.', 'In desserts, in cheese cake toppings in packets, in mousse mixtures in packets.', '', 'T - may be of animal origin;', 'Esters of Monoglycerides and Diglycerides of Fatty Acids and Citric Acid', 'Emulsifier, stabilizer, flour processing agent.', 'In desserts, in cheese cake toppings in packets, in mousse mixtures in packets.', '', 'T - may be of animal origin;'),
    ('E122', 'http://konservantai.lt/e122-azorubinas-karmosinas', 'Azorubinas, karmosinas', TRUE, '', 'Pudinguose, gėrimuose, saldumynuose konditerijoje, marcipane.', 'Kai kuriose šalyse uždraustas (JAV, Kanadoje).', '', 'Azorubine, Carmoisine', '', 'In puddings, beverages, confections, and marzipan.', 'Banned in some countries (USA, Canada).', ''),
    ('E525', 'http://konservantai.lt/e525-kalio-hidroksidas', 'Kalio hidroksidas', FALSE, '', 'Kakavoje, sūrio produktuose, juodose alyvuogėse.', 'Kai kuriose šalyse uždraustas (Australijoje / Naujojoje Zelandijoje).', '', 'Potassium Hydroxide', '', 'In cocoa, cheese products, black olives.', 'Banned in some countries (Australia / New Zealand).', ''),
