-- SQL script generated from JSON data
-- Batch insert into aggregate.additives

-- Create table if it does not exist
CREATE TABLE IF NOT EXISTS aggregate.additives (
    code TEXT PRIMARY KEY,
    url TEXT,
    name_lt TEXT,
    is_dangerous BOOLEAN,
    general_usage_in_food_industry_lt TEXT,
    usage_in_foods_lt TEXT,
    other_information_lt TEXT,
    damage_lt TEXT,
    name_en TEXT,
    general_usage_in_food_industry_en TEXT,
    usage_in_foods_en TEXT,
    other_information_en TEXT,
    damage_en TEXT
);

ON CONFLICT (code) DO UPDATE SET
    url = EXCLUDED.url,
    name_lt = EXCLUDED.name_lt,
    is_dangerous = EXCLUDED.is_dangerous,
    general_usage_in_food_industry_lt = EXCLUDED.general_usage_in_food_industry_lt,
    usage_in_foods_lt = EXCLUDED.usage_in_foods_lt,
    other_information_lt = EXCLUDED.other_information_lt,
    damage_lt = EXCLUDED.damage_lt,
    name_en = EXCLUDED.name_en,
    general_usage_in_food_industry_en = EXCLUDED.general_usage_in_food_industry_en,
    usage_in_foods_en = EXCLUDED.usage_in_foods_en,
    other_information_en = EXCLUDED.other_information_en,
    damage_en = EXCLUDED.damage_en;

